// --- Order Service ---

type OrderServer struct {
	mu      sync.RWMutex
	orders  map[string]*Order
	counter int
}

func NewOrderServer() *OrderServer {
	return &OrderServer{
		orders: make(map[string]*Order),
	}
}

func (s *OrderServer) CreateOrder(ctx context.Context, req *CreateOrderRequest) (*Order, error) {
	if req.UserId == "" {
		return nil, status.Errorf(codes.InvalidArgument, "user_id is required")
	}
	if len(req.Items) == 0 {
		return nil, status.Errorf(codes.InvalidArgument, "at least one item is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	s.counter++
	var total float64
	for _, item := range req.Items {
		total += item.Price * float64(item.Quantity)
	}

	order := &Order{
		Id:        fmt.Sprintf("order-%d", s.counter),
		UserId:    req.UserId,
		Items:     req.Items,
		Total:     total,
		Status:    "PENDING",
		CreatedAt: timestamppb.Now(),
	}
	s.orders[order.Id] = order

	log.Printf("[OrderService] Created order: %s for user %s (total: %.2f)", order.Id, order.UserId, order.Total)
	return order, nil
}

func (s *OrderServer) GetOrder(ctx context.Context, req *GetOrderRequest) (*Order, error) {
	if req.Id == "" {
		return nil, status.Errorf(codes.InvalidArgument, "order id is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	order, ok := s.orders[req.Id]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "order %s not found", req.Id)
	}

	log.Printf("[OrderService] Retrieved order: %s", order.Id)
	return order, nil
}

func (s *OrderServer) ListOrders(ctx context.Context, req *ListOrdersRequest) (*ListOrdersResponse, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	pageSize := int(req.PageSize)
	if pageSize <= 0 {
		pageSize = 10
	}

	var orders []*Order
	for _, o := range s.orders {
		if req.UserId != "" && o.UserId != req.UserId {
			continue
		}
		orders = append(orders, o)
		if len(orders) >= pageSize {
			break
		}
	}

	log.Printf("[OrderService] Listed %d orders", len(orders))
	return &ListOrdersResponse{
		Orders:        orders,
		NextPageToken: "",
	}, nil
}

func (s *OrderServer) CancelOrder(ctx context.Context, req *CancelOrderRequest) (*Order, error) {
	if req.Id == "" {
		return nil, status.Errorf(codes.InvalidArgument, "order id is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	order, ok := s.orders[req.Id]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "order %s not found", req.Id)
	}

	if order.Status == "CANCELLED" {
		return nil, status.Errorf(codes.FailedPrecondition, "order %s is already cancelled", req.Id)
	}
	if order.Status == "COMPLETED" {
		return nil, status.Errorf(codes.FailedPrecondition, "cannot cancel completed order %s", req.Id)
	}

	order.Status = "CANCELLED"
	log.Printf("[OrderService] Cancelled order: %s (reason: %s)", order.Id, req.Reason)
	return order, nil
}

// --- Payment Service ---

type PaymentServer struct {
	mu       sync.RWMutex
	payments map[string]*Payment
	counter  int
}

func NewPaymentServer() *PaymentServer {
	return &PaymentServer{
		payments: make(map[string]*Payment),
	}
}

func (s *PaymentServer) ProcessPayment(ctx context.Context, req *ProcessPaymentRequest) (*Payment, error) {
	if req.OrderId == "" {
		return nil, status.Errorf(codes.InvalidArgument, "order_id is required")
	}
	if req.Amount <= 0 {
		return nil, status.Errorf(codes.InvalidArgument, "amount must be positive")
	}
	if req.Currency == "" {
		return nil, status.Errorf(codes.InvalidArgument, "currency is required")
	}
	if req.Method == "" {
		return nil, status.Errorf(codes.InvalidArgument, "payment method is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	s.counter++
	payment := &Payment{
		Id:            fmt.Sprintf("pay-%d", s.counter),
		OrderId:       req.OrderId,
		Amount:        req.Amount,
		Currency:      req.Currency,
		Status:        "COMPLETED",
		Method:        req.Method,
		TransactionId: fmt.Sprintf("txn-%d-%d", s.counter, time.Now().UnixNano()),
		CreatedAt:     timestamppb.Now(),
	}
	s.payments[payment.Id] = payment

	log.Printf("[PaymentService] Processed payment: %s for order %s (%.2f %s via %s)",
		payment.Id, payment.OrderId, payment.Amount, payment.Currency, payment.Method)
	return payment, nil
}

func (s *PaymentServer) GetPayment(ctx context.Context, req *GetPaymentRequest) (*Payment, error) {
	if req.Id == "" {
		return nil, status.Errorf(codes.InvalidArgument, "payment id is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	payment, ok := s.payments[req.Id]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "payment %s not found", req.Id)
	}

	log.Printf("[PaymentService] Retrieved payment: %s", payment.Id)
	return payment, nil
}

func (s *PaymentServer) RefundPayment(ctx context.Context, req *RefundPaymentRequest) (*RefundResponse, error) {
	if req.PaymentId == "" {
		return nil, status.Errorf(codes.InvalidArgument, "payment_id is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	payment, ok := s.payments[req.PaymentId]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "payment %s not found", req.PaymentId)
	}

	if payment.Status == "REFUNDED" {
		return nil, status.Errorf(codes.FailedPrecondition, "payment %s is already refunded", req.PaymentId)
	}

	refundAmount := req.Amount
	if refundAmount <= 0 || refundAmount > payment.Amount {
		refundAmount = payment.Amount
	}

	payment.Status = "REFUNDED"

	refund := &RefundResponse{
		RefundId:  fmt.Sprintf("refund-%s", payment.Id),
		PaymentId: payment.Id,
		Amount:    refundAmount,
		Status:    "COMPLETED",
	}

	log.Printf("[PaymentService] Refunded payment: %s (amount: %.2f, reason: %s)",
		payment.Id, refundAmount, req.Reason)
	return refund, nil
}

func (s *PaymentServer) ListPayments(ctx context.Context, req *ListPaymentsRequest) (*ListPaymentsResponse, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	pageSize := int(req.PageSize)
	if pageSize <= 0 {
		pageSize = 10
	}

	var payments []*Payment
	for _, p := range s.payments {
		if req.OrderId != "" && p.OrderId != req.OrderId {
			continue
		}
		payments = append(payments, p)
		if len(payments) >= pageSize {
			break
		}
	}

	log.Printf("[PaymentService] Listed %d payments", len(payments))
	return &ListPaymentsResponse{
		Payments:      payments,
		NextPageToken: "",
	}, nil
}

