// ============================================================
// Logging interceptor for development
// ============================================================

func loggingUnaryInterceptor(
	ctx context.Context,
	req interface{},
	info *grpc.UnaryServerInfo,
	handler grpc.UnaryHandler,
) (interface{}, error) {
	start := time.Now()
	log.Printf("[gRPC] --> %s", info.FullMethod)

	resp, err := handler(ctx, req)

	duration := time.Since(start)
	if err != nil {
		st, _ := status.FromError(err)
		log.Printf("[gRPC] <-- %s [%s] %v (%v)", info.FullMethod, st.Code(), err, duration)
	} else {
		log.Printf("[gRPC] <-- %s [OK] (%v)", info.FullMethod, duration)
	}

	return resp, err
}

// ============================================================
// Recovery interceptor
// ============================================================

func recoveryUnaryInterceptor(
	ctx context.Context,
	req interface{},
	info *grpc.UnaryServerInfo,
	handler grpc.UnaryHandler,
) (resp interface{}, err error) {
	defer func() {
		if r := recover(); r != nil {
			log.Printf("[gRPC] PANIC recovered in %s: %v", info.FullMethod, r)
			err = status.Errorf(codes.Internal, "internal server error")
		}
	}()
	return handler(ctx, req)
}

// ============================================================
// Main
// ============================================================

func main() {
	port := ":50051"

	lis, err := net.Listen("tcp", port)
	if err != nil {
		log.Fatalf("Failed to listen on %s: %v", port, err)
	}

	// Create gRPC server with interceptors for development
	grpcServer := grpc.NewServer(
		grpc.ChainUnaryInterceptor(
			recoveryUnaryInterceptor,
			loggingUnaryInterceptor,
		),
	)

	// Initialize and register service handlers
	userService := NewUserManagementServer()
	orderService := NewOrderServer()
	paymentService := NewPaymentServer()

	registerUserManagementService(grpcServer, userService)
	registerOrderService(grpcServer, orderService)
	registerPaymentService(grpcServer, paymentService)

	// Enable gRPC reflection for development and testing
	// This allows tools like grpcurl, grpcui, Evans, and Postman
	// to discover services without .proto files
	reflection.Register(grpcServer)

	// Seed some test data for development
	seedTestData(userService, orderService, paymentService)

	log.Println("============================================")
	log.Println("  Microservices gRPC Server (Development)")
	log.Println("============================================")
	log.Printf("  Listening on %s", port)
	log.Println("  Reflection: ENABLED")
	log.Println("")
	log.Println("  Registered Services:")
	log.Println("    - microservices.UserManagementService")
	log.Println("      * CreateUser, GetUser, UpdateUser, DeleteUser, ListUsers")
	log.Println("    - microservices.OrderService")
	log.Println("      * CreateOrder, GetOrder, ListOrders, CancelOrder")
	log.Println("    - microservices.PaymentService")
	log.Println("      * ProcessPayment, GetPayment, RefundPayment, ListPayments")
	log.Println("")
	log.Println("  Test with grpcurl:")
	log.Println("    grpcurl -plaintext localhost:50051 list")
	log.Println("    grpcurl -plaintext localhost:50051 describe")
	log.Println("    grpcurl -plaintext -d '{\"email\":\"test@example.com\",\"name\":\"Test User\"}' localhost:50051 microservices.UserManagementService/CreateUser")
	log.Println("============================================")

	if err := grpcServer.Serve(lis); err != nil {
		log.Fatalf("Failed to serve: %v", err)
	}
}

func seedTestData(userSvc *UserManagementServer, orderSvc *OrderServer, paymentSvc *PaymentServer) {
	ctx := context.Background()

	// Create sample users
	user1, _ := userSvc.CreateUser(ctx, &CreateUserRequest{
		Email: "alice@example.com",
		Name:  "Alice Johnson",
	})
	user2, _ := userSvc.CreateUser(ctx, &CreateUserRequest{
		Email: "bob@example.com",
		Name:  "Bob Smith",
	})

	// Create sample orders
	order1, _ := orderSvc.CreateOrder(ctx, &CreateOrderRequest{
		UserId: user1.Id,
		Items: []*OrderItem{
			{ProductId: "prod-1", Quantity: 2, Price: 29.99},
			{ProductId: "prod-2", Quantity: 1, Price: 49.99},
		},
	})
	orderSvc.CreateOrder(ctx, &CreateOrderRequest{
		UserId: user2.Id,
		Items: []*OrderItem{
			{ProductId: "prod-3", Quantity: 3, Price: 15.00},
		},
	})

	// Create sample payment
	paymentSvc.ProcessPayment(ctx, &ProcessPaymentRequest{
		OrderId:  order1.Id,
		Amount:   order1.Total,
		Currency: "USD",
		Method:   "credit_card",
	})

	log.Println("[Seed] Test data created: 2 users, 2 orders, 1 payment")
}